<?php session_start(); require 'db.php'; if(!isset($_SESSION['user_id'])) exit; $uid=$_SESSION['user_id']; $cid=$_POST['comment_id']; $chk=$pdo->prepare("SELECT * FROM comment_likes WHERE user_id=? AND comment_id=?"); $chk->execute([$uid,$cid]); if($chk->fetch()){ $pdo->prepare("DELETE FROM comment_likes WHERE user_id=? AND comment_id=?")->execute([$uid,$cid]); $l=false; }else{ $pdo->prepare("INSERT INTO comment_likes (user_id, comment_id) VALUES (?,?)")->execute([$uid,$cid]); $l=true; } $c=$pdo->prepare("SELECT COUNT(*) FROM comment_likes WHERE comment_id=?"); $c->execute([$cid]); echo json_encode(['success'=>true,'likes'=>$c->fetchColumn(),'liked'=>$l]); ?>
